LIB="/tmp/sv-bb6bd5ee4a564865ae7d9325325fc46e/symbols/libmonosgen-2.0.so"

# Dump all symbols sorted by address, find which function each unknown address falls into
# We need to find functions containing 0x2f4b20 and 0x2f4c84
aarch64-linux-gnu-nm -D --defined-only "$LIB" 2>/dev/null | sort | awk '
{
    addr = strtonum("0x" $1)
    type = $2
    name = $3
    if (type == "T" || type == "t" || type == "W" || type == "w") {
        # Only consider code symbols
        entries[n++] = addr " " name
    }
}
END {
    targets[0] = 0x2f4b20
    targets[1] = 0x2f4c84
    for (t = 0; t < 2; t++) {
        target = targets[t]
        best_addr = 0
        best_name = "??"
        for (i = 0; i < n; i++) {
            split(entries[i], parts, " ")
            a = parts[1] + 0
            nm = parts[2]
            if (a <= target && a > best_addr) {
                best_addr = a
                best_name = nm
            }
        }
        printf "0x%x -> %s+0x%x (symbol at 0x%x)\n", target, best_name, target - best_addr, best_addr
    }
}'

