# Check section layout in the actual binary (not debug file)
aarch64-linux-gnu-readelf -S "$LIB" 2>/dev/null | grep -E "\.text|\.data|\.rodata|\.bss" | head -10

echo "---"
# Check what section 0x2f4b20 falls in
aarch64-linux-gnu-readelf -S "$LIB" 2>/dev/null | awk '
/\[/ {
    if (match($0, /\] \.([^ ]+)/, m)) {
        name = m[1]
    }
    for (i=1; i<=NF; i++) {
        if (length($i) == 16 && $i ~ /^[0-9a-f]+$/) {
            addr = strtonum("0x" $i)
            if (addr > 0 && addr < 0x400000) {
                # get the next field as size
                sizes[name] = addr
                break
            }
        }
    }
}
'
